# Prompt: Write a Python Envoy External Authorization service. Implement gRPC service that receives CheckRequest messages and returns CheckResponse. Accept custom headers from requests and make authorization decisions. This is for our custom auth integration with Envoy.
# Category: envoy_header_manipulation

import grpc
from concurrent import futures
import time
from envoy.service.auth.v3 import external_auth_pb2
from envoy.service.auth.v3 import external_auth_pb2_grpc
from envoy.type.v3 import http_status_pb2
from google.rpc import status_pb2, code_pb2


class AuthorizationService(external_auth_pb2_grpc.AuthorizationServicer):
    def __init__(self, authorized_tokens=None, required_headers=None):
        self.authorized_tokens = authorized_tokens or {"valid-token-123", "admin-token-456"}
        self.required_headers = required_headers or []
        
    def Check(self, request, context):
        http_request = request.attributes.request.http
        headers = http_request.headers
        
        auth_header = headers.get("authorization", "")
        custom_header = headers.get("x-custom-auth", "")
        
        for required_header in self.required_headers:
            if required_header not in headers:
                return self._create_denied_response(
                    f"Missing required header: {required_header}",
                    403
                )
        
        if auth_header.startswith("Bearer "):
            token = auth_header[7:]
            if token in self.authorized_tokens:
                return self._create_ok_response(token)
            else:
                return self._create_denied_response("Invalid token", 401)
        
        if custom_header in self.authorized_tokens:
            return self._create_ok_response(custom_header)
        
        return self._create_denied_response("Unauthorized", 401)
    
    def _create_ok_response(self, token):
        response = external_auth_pb2.CheckResponse()
        response.status.code = code_pb2.OK
        
        response.ok_response.headers.add(
            header=external_auth_pb2.HeaderValueOption(
                header=external_auth_pb2.HeaderValue(
                    key="x-auth-user",
                    value=token
                )
            )
        )
        
        response.ok_response.headers.add(
            header=external_auth_pb2.HeaderValueOption(
                header=external_auth_pb2.HeaderValue(
                    key="x-auth-status",
                    value="authorized"
                )
            )
        )
        
        return response
    
    def _create_denied_response(self, message, status_code):
        response = external_auth_pb2.CheckResponse()
        response.status.code = code_pb2.PERMISSION_DENIED
        response.status.message = message
        
        response.denied_response.status.code = getattr(
            http_status_pb2.StatusCode, f"_{status_code}", 
            http_status_pb2.StatusCode.Forbidden
        )
        
        response.denied_response.headers.add(
            header=external_auth_pb2.HeaderValue(
                key="content-type",
                value="text/plain"
            )
        )
        
        response.denied_response.body = message
        
        return response


def serve(port=50051, authorized_tokens=None, required_headers=None):
    server = grpc.server(futures.ThreadPoolExecutor(max_workers=10))
    
    auth_service = AuthorizationService(
        authorized_tokens=authorized_tokens,
        required_headers=required_headers
    )
    
    external_auth_pb2_grpc.add_AuthorizationServicer_to_server(
        auth_service, server
    )
    
    server.add_insecure_port(f'[::]:{port}')
    server.start()
    
    print(f"Authorization server started on port {port}")
    
    try:
        while True:
            time.sleep(86400)
    except KeyboardInterrupt:
        server.stop(0)


